import Foundation

// MARK: - Environment Configuration

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev-api.example.com"
        case .staging:
            return "https://staging-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

// MARK: - Network Error

enum NetworkError: LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case serverError(statusCode: Int, message: String?)
    case unauthorized
    case networkFailure(Error)
    case unknown
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received from server"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .serverError(let statusCode, let message):
            return "Server error (\(statusCode)): \(message ?? "Unknown")"
        case .unauthorized:
            return "Unauthorized. Please log in again."
        case .networkFailure(let error):
            return "Network failure: \(error.localizedDescription)"
        case .unknown:
            return "An unknown error occurred"
        }
    }
}

// MARK: - HTTP Method

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case delete = "DELETE"
}

// MARK: - API Endpoint

enum APIEndpoint {
    case login
    case register
    case refreshToken
    case userProfile
    case users
    case user(id: String)
    case updateProfile
    
    var path: String {
        switch self {
        case .login:
            return "/auth/login"
        case .register:
            return "/auth/register"
        case .refreshToken:
            return "/auth/refresh"
        case .userProfile:
            return "/users/me"
        case .users:
            return "/users"
        case .user(let id):
            return "/users/\(id)"
        case .updateProfile:
            return "/users/me"
        }
    }
    
    var method: HTTPMethod {
        switch self {
        case .login, .register, .refreshToken:
            return .post
        case .userProfile, .users, .user:
            return .get
        case .updateProfile:
            return .put
        }
    }
}

// MARK: - Token Storage

final class TokenStorage {
    static let shared = TokenStorage()
    
    private let accessTokenKey = "com.app.accessToken"
    private let refreshTokenKey = "com.app.refreshToken"
    
    private init() {}
    
    var accessToken: String? {
        get { UserDefaults.standard.string(forKey: accessTokenKey) }
        set { UserDefaults.standard.set(newValue, forKey: accessTokenKey) }
    }
    
    var refreshToken: String? {
        get { UserDefaults.standard.string(forKey: refreshTokenKey) }
        set { UserDefaults.standard.set(newValue, forKey: refreshTokenKey) }
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
    
    var isLoggedIn: Bool {
        return accessToken != nil
    }
}

