// MARK: - Network Client

final class NetworkClient {
    static let shared = NetworkClient()
    
    private let session: URLSession
    private var environment: Environment
    private let tokenStorage: TokenStorage
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private var isRefreshingToken = false
    private var pendingRequests: [(Result<Data, NetworkError>) -> Void] = []
    private let requestQueue = DispatchQueue(label: "com.app.networkClient.queue")
    
    private init(
        environment: Environment = .development,
        tokenStorage: TokenStorage = .shared
    ) {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        
        self.session = URLSession(configuration: configuration)
        self.environment = environment
        self.tokenStorage = tokenStorage
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
    }
    
    // MARK: - Environment Configuration
    
    func setEnvironment(_ environment: Environment) {
        self.environment = environment
    }
    
    // MARK: - Core Request Method
    
    private func buildURL(endpoint: APIEndpoint, queryItems: [URLQueryItem]? = nil) -> URL? {
        var components = URLComponents(string: environment.baseURL + endpoint.path)
        components?.queryItems = queryItems
        return components?.url
    }
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Data? = nil,
        queryItems: [URLQueryItem]? = nil,
        authenticated: Bool = true
    ) -> URLRequest? {
        guard let url = buildURL(endpoint: endpoint, queryItems: queryItems) else {
            return nil
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.httpBody = body
        
        if authenticated, let token = tokenStorage.accessToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        return request
    }
    
    private func performRequest(
        _ request: URLRequest,
        completion: @escaping (Result<Data, NetworkError>) -> Void
    ) {
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                DispatchQueue.main.async {
                    completion(.failure(.networkFailure(error)))
                }
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                DispatchQueue.main.async {
                    completion(.failure(.unknown))
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                DispatchQueue.main.async {
                    completion(.success(data))
                }
            case 401:
                DispatchQueue.main.async {
                    completion(.failure(.unauthorized))
                }
            default:
                let errorMessage = try? JSONDecoder().decode(APIErrorResponse.self, from: data)
                DispatchQueue.main.async {
                    completion(.failure(.serverError(
                        statusCode: httpResponse.statusCode,
                        message: errorMessage?.message
                    )))
                }
            }
        }
        task.resume()
    }
    
    // MARK: - Generic Request with Decoding
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryItems: [URLQueryItem]? = nil,
        authenticated: Bool = true,
        retryOnUnauthorized: Bool = true,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        var bodyData: Data? = nil
        if let body = body {
            do {
                bodyData = try encoder.encode(body)
            } catch {
                completion(.failure(.decodingError(error)))
                return
            }
        }
        
        guard let urlRequest = buildRequest(
            endpoint: endpoint,
            body: bodyData,
            queryItems: queryItems,
            authenticated: authenticated
        ) else {
            completion(.failure(.invalidURL))
            return
        }
        
        performRequest(urlRequest) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let data):
                do {
                    let decoded = try self.decoder.decode(T.self, from: data)
                    completion(.success(decoded))
                } catch {
                    completion(.failure(.decodingError(error)))
                }
                
            case .failure(.unauthorized) where retryOnUnauthorized && authenticated:
                self.handleTokenRefresh { refreshResult in
                    switch refreshResult {
                    case .success:
                        // Retry the original request once
                        self.request(
                            endpoint: endpoint,
                            body: body,
                            queryItems: queryItems,
                            authenticated: authenticated,
                            retryOnUnauthorized: false,
                            completion: completion
                        )
                    case .failure(let error):
                        completion(.failure(error))
                    }
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Token Refresh
    
    private func handleTokenRefresh(completion: @escaping (Result<Void, NetworkError>) -> Void) {
        requestQueue.sync {
            pendingRequests.append { result in
                switch result {
                case .success:
                    completion(.success(()))
                case .failure(let error):
                    completion(.failure(error))
                }
            }
            
            guard !isRefreshingToken else { return }
            isRefreshingToken = true
        }
        
        guard let refreshToken = tokenStorage.refreshToken else {
            finishRefresh(with: .failure(.unauthorized))
            return
        }
        
        let refreshRequest = RefreshTokenRequest(refreshToken: refreshToken)
        
        guard let bodyData = try? encoder.encode(refreshRequest),
              let urlRequest = buildRequest(
                  endpoint: .refreshToken,
                  body: bodyData,
                  authenticated: false
              ) else {
            finishRefresh(with: .failure(.invalidURL))
            return
        }
        
        performRequest(urlRequest) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let data):
                do {
                    let response = try self.decoder.decode(RefreshTokenResponse.self, from: data)
                    self.tokenStorage.accessToken = response.accessToken
                    self.tokenStorage.refreshToken = response.refreshToken
                    self.finishRefresh(with: .success(data))
                } catch {
                    self.tokenStorage.clearTokens()
                    self.finishRefresh(with: .failure(.decodingError(error)))
                }
                
            case .failure(let error):
                self.tokenStorage.clearTokens()
                self.finishRefresh(with: .failure(error))
            }
        }
    }
    
    private func finishRefresh(with result: Result<Data, NetworkError>) {
        requestQueue.sync {
            isRefreshingToken = false
            let requests = pendingRequests
            pendingRequests.removeAll()
            
            DispatchQueue.main.async {
                requests.forEach { $0(result) }
            }
        }
    }
}

// MARK: - Auth Service

final class AuthService {
    private let networkClient: NetworkClient
    private let tokenStorage: TokenStorage
    
    init(
        networkClient: NetworkClient = .shared,
        tokenStorage: TokenStorage = .shared
    ) {
        self.networkClient = networkClient
        self.tokenStorage = tokenStorage
    }
    
    func login(
        email: String,
        password: String,
        completion: @escaping (Result<User, NetworkError>) -> Void
    ) {
        let body = LoginRequest(email: email, password: password)
        
        networkClient.request(
            endpoint: .login,
            body: body,
            authenticated: false,
            retryOnUnauthorized: false
        ) { [weak self] (result: Result<AuthResponse, NetworkError>) in
            switch result {
            case .success(let authResponse):
                self?.tokenStorage.accessToken = authResponse.accessToken
                self?.tokenStorage.refreshToken = authResponse.refreshToken
                completion(.success(authResponse.user))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func register(
        email: String,
        password: String,
        firstName: String,
        lastName: String,
        completion: @escaping (Result<User, NetworkError>) -> Void
    ) {
        let body = RegisterRequest(
            email: email,
            password: password,
            firstName: firstName,
            lastName: lastName
        )
        
        networkClient.request(
            endpoint: .register,
            body: body,
            authenticated: false,
            retryOnUnauthorized: false
        ) { [weak self] (result: Result<AuthResponse, NetworkError>) in
            switch result {
            case .success(let authResponse):
                self?.tokenStorage.accessToken = authResponse.accessToken
                self?.tokenStorage.refreshToken = authResponse.refreshToken
                completion(.success(authResponse.user))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func logout() {
        tokenStorage.clearTokens()
    }
    
    var isLoggedIn: Bool {
        return tokenStorage.isLoggedIn
    }
}

// MARK: - User Service

final class UserService {
    private let networkClient: NetworkClient
    
    init(networkClient: NetworkClient = .shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser(completion: @escaping (Result<User, NetworkError>) -> Void) {
        networkClient.request(endpoint: .userProfile, completion: completion)
    }
    
    func fetchUsers(
        page: Int = 1,
        perPage: Int = 20,
        completion: @escaping (Result<UsersResponse, NetworkError>) -> Void
    ) {
        let queryItems = [
            URLQueryItem(name: "page", value: "\(page)"),
            URLQueryItem(name: "per_page", value: "\(perPage)")
        ]
        
        networkClient.request(
            endpoint: .users,
            queryItems: queryItems,
            completion: completion
        )
    }
    
    func fetchUser(
        id: String,
        completion: @escaping (Result<User, NetworkError>) -> Void
    ) {
        networkClient.request(endpoint: .user(id: id), completion: completion)
    }
    
    func updateProfile(
        firstName: String? = nil,
        lastName: String? = nil,
        avatarURL: String? = nil,
        completion: @escaping (Result<User, NetworkError>) -> Void
    ) {
        let body = UpdateProfileRequest(
            firstName: firstName,
            lastName: lastName,
            avatarURL: avatarURL
        )
        
        networkClient.request(
            endpoint: .updateProfile,
            body: body,
            completion: completion
        )
    }
}

